package com.google.gson.internal.reflect;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.AccessibleObject;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class ReflectionHelperTest {

  static class TestRecord {
    // A record class requires Java 16+, but since we can't guarantee environment,
    // we will mock behavior instead.
  }

  static class NotRecord {
  }

  @BeforeAll
  static void setup() throws Exception {
    // Use reflection to set RECORD_HELPER to a mock for testing isRecord behavior
    RecordHelper mockRecordHelper = mock(RecordHelper.class);
    java.lang.reflect.Field recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);
    recordHelperField.set(null, mockRecordHelper);
  }

  @Test
  void testIsRecordTrue() throws Exception {
    RecordHelper mockRecordHelper = getRecordHelperMock();

    when(mockRecordHelper.isRecord(String.class)).thenReturn(true);

    boolean result = ReflectionHelper.isRecord(String.class);
    assertTrue(result);

    verify(mockRecordHelper).isRecord(String.class);
  }

  @Test
  void testIsRecordFalse() throws Exception {
    RecordHelper mockRecordHelper = getRecordHelperMock();

    when(mockRecordHelper.isRecord(Integer.class)).thenReturn(false);

    boolean result = ReflectionHelper.isRecord(Integer.class);
    assertFalse(result);

    verify(mockRecordHelper).isRecord(Integer.class);
  }

  private RecordHelper getRecordHelperMock() throws Exception {
    java.lang.reflect.Field recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);
    return (RecordHelper) recordHelperField.get(null);
  }
}
